# ADR-007 M3 exit-criterion oracle: the Julia mesh generated by
# `inla_mesh_2d` must be quantitatively comparable to the fmesher mesh
# produced from the *same* boundary and parameters, on three reference
# polygons (unit square, L-shape, convex hull of Meuse). The gate from
# plans/plan.md is:
#
#   |n_vertices_J - n_vertices_R| / n_vertices_R  ≤ 0.05
#   min_angle_J                                     ≥ max(20°, 0.95 · min_angle_R)
#   max_edge_J                                      ≤ 1.05 · max_edge_R
#
# Fixtures live at test/oracle/fixtures/fmesher_*.jld2 and are produced
# by scripts/generate-fixtures/spde/fmesher_*.R.
#
# Result (v0.1 core — recorded 2026-04-24):
#                     nv_J / nv_R    min_angle_J / R    max_edge_J / R
#   unit_square       fails          fails              fails
#   L-shape           0.106 (fail)   29.2° / 45.0°      0.309 / 0.250
#   Meuse hull        0.262 (fail)   25.9° / 30.1°      0.365 / 0.250
#
# The Julia Ruppert refinement in `DelaunayTriangulation.jl` uses an
# equilateral-area bound √3/4·max_edge², which is not tight for right or
# obtuse triangles — hence the max_edge excess. fmesher also does
# per-edge bisection that we don't yet match, producing tighter angles.
# These gaps are the ADR-007 signal that the `INLASPDEFmesher.jl`
# fallback (wrapping fmesher via BinaryBuilder) is needed for production
# parity. The parity-gate assertions are marked `@test_broken` until
# that work lands; the 20° minimum-angle floor (a hard Ruppert
# guarantee) is kept as a plain `@test` so regressions surface.

using JLD2
using LinearAlgebra: norm

const FIXTURE_DIR = joinpath(@__DIR__, "fixtures")

"""
    mesh_stats(points, triangles) -> (n_vertices, n_triangles,
                                      min_angle_deg, max_edge)

Julia-side recomputation of the same mesh statistics that the R helper
`mesh_to_list` in `_helpers.R` writes out. Deliberately duplicated so
the comparison is against the recorded fmesher numbers, not against
whatever Julia would have recomputed from the R mesh.
"""
function mesh_stats(points::AbstractMatrix, triangles::AbstractMatrix)
    nv = size(points, 1)
    nt = size(triangles, 1)
    min_angle = Inf
    max_edge = -Inf
    for k in 1:nt
        i, j, m = triangles[k, 1], triangles[k, 2], triangles[k, 3]
        P1 = @view points[i, :]
        P2 = @view points[j, :]
        P3 = @view points[m, :]
        e12 = norm(P2 - P1)
        e23 = norm(P3 - P2)
        e31 = norm(P1 - P3)
        max_edge = max(max_edge, e12, e23, e31)
        # Law of cosines.
        a1 = acos(clamp((e23^2 + e31^2 - e12^2) / (2 * e23 * e31), -1.0, 1.0))
        a2 = acos(clamp((e31^2 + e12^2 - e23^2) / (2 * e31 * e12), -1.0, 1.0))
        a3 = acos(clamp((e12^2 + e23^2 - e31^2) / (2 * e12 * e23), -1.0, 1.0))
        min_angle = min(min_angle, a1, a2, a3)
    end
    return (nv, nt, rad2deg(min_angle), max_edge)
end

function _check_parity(tag, julia_mesh, fxt)
    points = julia_mesh.points
    tris = julia_mesh.triangles
    nv_j, nt_j, min_ang_j, max_edge_j = mesh_stats(points, tris)

    mesh_r = fxt["mesh"]
    nv_r = Int(mesh_r["n_vertices"])
    min_ang_r = Float64(mesh_r["min_angle_deg"])
    max_edge_r = Float64(mesh_r["max_edge"])

    @testset "$tag" begin
        # Vertex count: within 5% of fmesher's count.
        # Marked `@test_broken` until INLASPDEFmesher.jl lands (ADR-007).
        rel_vcount = abs(nv_j - nv_r) / nv_r
        @test_broken rel_vcount ≤ 0.05
        # Min angle: Ruppert's 20° floor is a real guarantee we must meet.
        @test min_ang_j ≥ 20.0
        # fmesher-level tightness (95% of its angle) — deferred.
        @test_broken min_ang_j ≥ 0.95 * min_ang_r
        # Max edge: at most 5% bigger than fmesher's — deferred. Julia's
        # equilateral-area Ruppert bound leaves ~50% slack for right
        # triangles, so this gate won't pass without tighter refinement.
        @test_broken max_edge_j ≤ 1.05 * max_edge_r
    end
    return (; nv_j, nt_j, min_ang_j, max_edge_j,
              nv_r, min_ang_r, max_edge_r, rel_vcount = abs(nv_j - nv_r) / nv_r)
end

@testset "fmesher parity — unit square" begin
    fxt = load(joinpath(FIXTURE_DIR, "fmesher_unit_square.jld2"))["fixture"]
    boundary = fxt["boundary"]
    params = fxt["params"]
    mesh_j = inla_mesh_2d(;
        boundary  = boundary,
        max_edge  = params["max_edge"],
        min_angle = params["min_angle"],
        cutoff    = params["cutoff"],
        offset    = params["offset"],
    )
    _check_parity("unit_square", mesh_j, fxt)
end

@testset "fmesher parity — L-shape" begin
    fxt = load(joinpath(FIXTURE_DIR, "fmesher_lshape.jld2"))["fixture"]
    boundary = fxt["boundary"]
